import { createClient } from '@/utils/supabase/server'
import Link from 'next/link'
import { LayoutDashboard, Folders, UserCircle, MessageSquare, Save, ArrowLeft } from 'lucide-react'
import ProfileForm from '@/components/ProfileForm'

export default async function AdminProfile() {
  const supabase = await createClient()
  
  // Ambil data profil saat ini
  const { data: profile } = await supabase
    .from('Profile')
    .select('*')
    .single()

  const menuItems = [
    { name: 'Dashboard', icon: <LayoutDashboard size={20} />, href: '/admin' },
    { name: 'Profil', icon: <UserCircle size={20} />, href: '/admin/profile', active: true },
    { name: 'Proyek', icon: <Folders size={20} />, href: '/admin/projects' },
    { name: 'Pesan', icon: <MessageSquare size={20} />, href: '/admin/messages' },
  ]

  return (
    <div className="min-h-screen bg-[#050505] text-white flex font-jakarta">
      {/* Sidebar */}
      <aside className="w-64 border-r border-white/5 bg-black/50 backdrop-blur-xl p-6 hidden md:block">
        <div className="mb-10 text-xl font-bold font-outfit tracking-tighter">
          RIDHO<span className="text-teal-500">ADMIN.</span>
        </div>
        <nav className="space-y-2">
          {menuItems.map((item) => (
            <Link key={item.name} href={item.href} className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${item.active ? 'bg-teal-500 text-black font-bold' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}>
              {item.icon}
              {item.name}
            </Link>
          ))}
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-8 overflow-y-auto">
        <div className="max-w-3xl">
          <header className="mb-10 flex items-center gap-4">
            <Link href="/admin" className="p-2 hover:bg-white/5 rounded-full transition-all text-gray-400">
              <ArrowLeft size={24} />
            </Link>
            <div>
              <h1 className="text-2xl font-bold">Edit Profil</h1>
              <p className="text-gray-500 text-sm">Perbarui informasi publik Anda yang muncul di halaman utama.</p>
            </div>
          </header>

          <div className="bg-white/5 border border-white/10 rounded-3xl p-8">
            {/* Kita butuh Client Component untuk handle Form */}
            <ProfileForm initialData={profile} />
          </div>
        </div>
      </main>
    </div>
  )
}
